import 'package:flutter/material.dart';import 'package:cloud_firestore/cloud_firestore.dart';import 'package:provider/provider.dart';import '../providers/player_provider.dart';import 'player_profile_view.dart';import '../widgets/top_bar.dart';
class FriendsView extends StatelessWidget{const FriendsView({super.key});@override Widget build(BuildContext context){final player=Provider.of<PlayerProvider>(context);final fs=FirebaseFirestore.instance;return Directionality(textDirection:TextDirection.rtl,child:DefaultTabController(length:2,child:Scaffold(backgroundColor:const Color(0xFF1A1A1D),appBar:AppBar(backgroundColor:Colors.black87,title:const Text('الأصدقاء 👥',style:TextStyle(color:Colors.amber)),centerTitle:true,iconTheme:const IconThemeData(color:Colors.amber),bottom:const TabBar(indicatorColor:Colors.amber,labelColor:Colors.amber,unselectedLabelColor:Colors.white54,tabs:[Tab(text:'قائمة الأصدقاء'),Tab(text:'طلبات الصداقة')])),body:TabBarView(children:[
  // 🟢 1. قائمة الأصدقاء 🟢
  StreamBuilder<QuerySnapshot>(stream:fs.collection('players').doc(player.uid).collection('friends').snapshots(),builder:(ctx,snap){if(!snap.hasData)return const Center(child:CircularProgressIndicator(color:Colors.amber));if(snap.data!.docs.isEmpty)return const Center(child:Text('لا يوجد لديك أصدقاء حالياً.',style:TextStyle(color:Colors.white54)));return ListView.builder(itemCount:snap.data!.docs.length,itemBuilder:(ctx,i){final d=snap.data!.docs[i].data() as Map<String,dynamic>;return Card(color:Colors.black45,margin:const EdgeInsets.symmetric(horizontal:10,vertical:5),child:ListTile(leading:const CircleAvatar(backgroundColor:Colors.blue,child:Icon(Icons.person,color:Colors.white)),title:Text(d['name']??'مجهول',style:const TextStyle(color:Colors.white,fontWeight:FontWeight.bold)),trailing:const Icon(Icons.arrow_forward_ios,color:Colors.white24,size:14),onTap:()=>_openProfile(context,d['uid'])));});}),
  // 🟢 2. طلبات الصداقة المعلقة 🟢
  StreamBuilder<QuerySnapshot>(stream:fs.collection('players').doc(player.uid).collection('friend_requests').snapshots(),builder:(ctx,snap){if(!snap.hasData)return const Center(child:CircularProgressIndicator(color:Colors.amber));if(snap.data!.docs.isEmpty)return const Center(child:Text('لا توجد طلبات معلقة.',style:TextStyle(color:Colors.white54)));return ListView.builder(itemCount:snap.data!.docs.length,itemBuilder:(ctx,i){final d=snap.data!.docs[i].data() as Map<String,dynamic>;return Card(color:Colors.black45,margin:const EdgeInsets.symmetric(horizontal:10,vertical:5),child:ListTile(leading:const CircleAvatar(backgroundColor:Colors.orange,child:Icon(Icons.person_add,color:Colors.white)),title:Text(d['senderName']??'مجهول',style:const TextStyle(color:Colors.white,fontWeight:FontWeight.bold)),subtitle:const Text('يريد إضافتك كصديق',style:TextStyle(color:Colors.white54,fontSize:12)),trailing:Row(mainAxisSize:MainAxisSize.min,children:[IconButton(icon:const Icon(Icons.check_circle,color:Colors.green),onPressed:()=>player.acceptFriend(d['senderId'],d['senderName'])),IconButton(icon:const Icon(Icons.cancel,color:Colors.red),onPressed:()=>player.rejectFriend(d['senderId']))])));});})
]))));}
void _openProfile(BuildContext context,String uid)async{showDialog(context:context,barrierDismissible:false,builder:(c)=>const Center(child:CircularProgressIndicator(color:Colors.amber)));final p=Provider.of<PlayerProvider>(context,listen:false);final d=await p.getPlayerById(uid);if(context.mounted){Navigator.pop(context);if(d!=null){Navigator.push(context,MaterialPageRoute(builder:(_)=>Directionality(textDirection:TextDirection.rtl,child:Scaffold(backgroundColor:const Color(0xFF1A1A1D),body:SafeArea(top:false,child:Consumer<PlayerProvider>(builder:(context,player,child)=>Column(children:[TopBar(cash:player.cash,gold:player.gold,energy:player.energy,maxEnergy:player.maxEnergy,courage:player.courage,maxCourage:player.maxCourage,health:player.health,maxHealth:player.maxHealth,prestige:player.prestige,maxPrestige:player.maxPrestige,playerName:player.playerName,profilePicUrl:player.profilePicUrl,level:player.crimeLevel,currentXp:player.crimeXP,maxXp:player.xpToNextLevel,isVIP:player.isVIP),Expanded(child:PlayerProfileView(targetUid:uid,previewName:d['playerName'],previewPicUrl:d['profilePicUrl'],previewIsVIP:d['isVIP']==true,onBack:()=>Navigator.pop(context)))]) ))))));}}}}